// ── EMBEDDED (denormalized) ──────────────────────────────────
// Good when you always want author info with the book
{
  _id: ObjectId(),
  title: '1984',
  author: {
    name: 'George Orwell',
    nationality: 'British',
    born: 1903
  }
}
// Pros: db.books.findOne({ title:'1984' }) gives everything
// Cons: if Orwell's bio changes, update every book document

// ── REFERENCED (normalized) ──────────────────────────────────
// Good when author data is updated independently
{ _id: ObjectId(), title: '1984', authorId: ObjectId('...') }
// Separate authors collection:
{ _id: ObjectId('...'), name: 'George Orwell', nationality: 'British' }
// Cons: need $lookup to get author name

// One user, one profile — embed it
{
  _id: ObjectId(),
  username: 'alice',
  profile: {           // embedded one-to-one
    bio: 'Bookworm',
    avatar: 'alice.jpg',
    joinedAt: ISODate()
  }
}

// A book has many tags — always small, always read together → EMBED
{
  _id: ObjectId(),
  title: '1984',
  tags: ['surveillance', 'dystopia', 'political']  // max ~10 tags
}

// A user has many orders — could be thousands, queried independently → REFERENCE
// orders collection:
{ _id: ObjectId(), customerId: ObjectId('...'), totalAmount: 59.99, ... }
// users collection:
{ _id: ObjectId(), name: 'Alice' }  // NO orders array here — would grow unbounded

// A book can have many genres; a genre applies to many books
// Store the array of genre strings directly (denormalized)
{
  _id: ObjectId(),
  title: '1984',
  genres: ['dystopia', 'fiction', 'classic']  // denormalized M:M
}

// Or with ObjectId references if genres have rich metadata:
{ _id: ObjectId(), title: '1984', genreIds: [ObjectId('...'), ObjectId('...')] }
// genres collection:
{ _id: ObjectId('...'), name: 'dystopia', description: '...' }

// Instead of just storing the authorId:
{ _id: ObjectId(), title: '1984', authorId: ObjectId('...') }

// Store authorId PLUS the fields you always need:
{
  _id: ObjectId(),
  title: '1984',
  authorId: ObjectId('...'),
  authorName: 'George Orwell',   // cached field
  authorNationality: 'British'   // cached field
}
// You can now display the book with its author info in ONE query.
// Trade-off: if the author updates their name, you must update all books too.

// Product document: embed only the 5 most recent reviews for quick display
{
  _id: ObjectId(),
  title: 'Dune',
  recentReviews: [   // last 5 only — fast to load
    { user: 'alice', rating: 5, text: 'Incredible!' },
    ...
  ]
}

// All reviews live in a separate collection:
{ _id: ObjectId(), bookId: ObjectId('...'), user: 'bob', rating: 4, text: '...' }

// ❌ Anti-pattern: one document per reading (too many small docs)
{ sensorId: 1, value: 23.5, timestamp: ISODate('2024-01-01T10:00:00') }
{ sensorId: 1, value: 23.7, timestamp: ISODate('2024-01-01T10:01:00') }

// ✅ Bucket: group an hour of readings into one document
{
  sensorId: 1,
  hour: ISODate('2024-01-01T10:00:00'),
  readings: [
    { minute: 0, value: 23.5 },
    { minute: 1, value: 23.7 },
    ...
  ],
  count: 60,
  sum: 1412.4   // pre-aggregated for fast averages
}

// Normal product: embed up to 50 reviews directly
{ _id: ObjectId(), title: 'Dune', reviews: [...50 reviews...] }

// Viral product with 100,000 reviews: flag it as an outlier
{
  _id: ObjectId(),
  title: 'Best-Seller XYZ',
  reviews: [...first 50...],  // keep a sample for quick display
  hasOverflowReviews: true    // flag: extra reviews are in the reviews collection
}
// Application checks hasOverflowReviews and queries separately if needed

// Old document (version 1): address is a string
{ _id: ObjectId(), name: 'Alice', address: '123 Main St', schemaVersion: 1 }

// New document (version 2): address is an embedded object
{ _id: ObjectId(), name: 'Bob', address: { street: '456 Oak Ave', city: 'NYC' }, schemaVersion: 2 }

// Application code:
function getCity(user) {
  if (user.schemaVersion === 1) return user.address.split(',')[1]?.trim();
  return user.address.city;  // version 2 format
}
